# ── apply ──────────────────────────────────────────────────────────
en_data = load_json("en")
for locale in LOCALES:
    data = load_json(locale)
    count = 0
    for key, translations in T.items():
        full_key = f"Terms.{key}"
        en_val = get_nested(en_data, full_key)
        current_val = get_nested(data, full_key)
        if en_val is not None and current_val == en_val and locale in translations:
            set_nested(data, full_key, translations[locale])
            count += 1
    save_json(locale, data)
    print(f"  {locale}: {count} keys translated")

print("\nPart 1 complete.")
